[[module css]]
@import url("https://lemoncat233.github.io/supreroomartists/Suprematism/suprematism.css");
:root {
   --header-title: " 阴风乍起，新魂不散 ";
   --banner-title: "    ";
   --banner-subtitle: "    ";

   --global-white-color:0,47,19;/* 整个页面的背景色 */
   --global-pale-color:0,102,51,0;
   --global-light-color:61,145,64;/* 顶栏（原创图书馆，社区……）下面那根线 */
   --global-dark-color: 0,102,51;/* 暗色div区域 */
   --global-black-color: 255,255,255;/* 文本颜色*/
   --global-accent-2: 46,139,87;/* 标题分割线颜色*/
   --global-accent-3: 0,199,140;
   --global-accent-1: 186,0,0;
   --new-color-1: 0,255,127;/* 浅色div*/
   --new-color-2: 100,0,0;
   --light-ui-bg: 0,255,127,0.7;/* ui*/
   --search-hover-bg: 86,75,61;
   --openmenu-hover-bg: 86,75,61;
   --user-hover-bg: 86,75,61;
   --user-drop-bg: 86,75,61;
   --topbar-hover-bg: 0,255,127;/* 顶栏原创图书馆等被选中后的颜色*/
   --bottombar-bg: 0,0,0,0;
   --rate-bg: 0,0,0,0;
   --menu-bg: 56,94,15;/* 侧栏背景颜色*/

   --header-font: '演示夏行楷';

   --pale-gray-monochrome: 0,255,127;;/* 顶栏折叠内容被选择后的颜色*/
   --gray-monochrome: 72,69,60;

#header-extra-div-1 {
   backdrop-filter: 128rem;
}

#extra-div-1 {
   position: absolute;
   width: 100%;
   height: 100%;
   z-index: -3;
   top: 0;
   left: 0;
   background-image: url("https://001-cn.wikidot.com/local--files/ytdm/paper");
   background-size: 180%;
   background-repeat: repeat-x;
   background-position: top left;
}

#extra-div-2 {
   position: absolute;
   width: 100%;
   height: 100%;
   z-index: -2;
   top: 0;
   left: 0;
   background-image: linear-gradient(180deg, rgba(var(--global-black-color),0) 0%, rgba(var(--global-white-color),1) 36%);
   background-size: 16rem 34rem;
   background-repeat: repeat-x;
   background-position: left top;
}

#extra-div-3 {
   position: fixed;
   width: 100%;
   height: 100%;
   z-index: -1;
   background-image: url(
"http://backrooms-cn-dielsalder.wikidot.com/local--files/level-da-47/%E6%A0%91%E6%9E%9D%E5%AD%97.png"),url(
"http://backrooms-cn-dielsalder.wikidot.com/local--files/level-da-47/%E8%9C%98%E8%9B%9B%E7%BD%91.png");
   background-size:20%,20%;
   background-repeat: no-repeat,no-repeat;
   background-position: bottom right,bottom left;
   top: 0;
   left: 0;
}

#page-title {
   color:rgba(var(--global-accent-2));
   border-bottom: var(--global-border-width) solid rgb(var(--global-accent-2),0.8);
}

#side-bar {
   background:rgba(var(--global-white-color));
}

#side-bar .side-block.media {
   background-color: rgba(var(--global-dark-color)) !important;
   background-image: url("https://001-cn.wikidot.com/local--files/ytdm/the-poem");
   background-repeat: repeat;
   background-size: 80px auto;
}

#side-bar .side-block .heading {
   background: rgba(var(--global-black-color),0.2);
   color: rgba(var(--global-black-color));
   text-align: center;
}

#top-bar > div > ul > li > ul > li {
   background-color: rgba(86,75,61,0.8);
   border: 0px;
}

#top-bar > div > ul > :is(li, li:hover, li:focus, li.sfhover, li:focus-within) > ul > li a {
    color: rgb(203,164,108);
}

#footer {
   border-top: 0.1rem solid rgba(var(--global-black-color), 0);
}

hr {
   border-top: var(--global-border-width) solid rgba(var(--global-accent-2));
}

.divider {
   border: none;
   height: 10px;
   background-image: var(--hr-bg);
   background-repeat: no-repeat;
   background-size:70%;
   background-position: center;
}

:is(blockquote, .blockquote, div.blockquote, [class*=blockquote]) {
   margin: 1rem 0;
   padding: 0 1rem;
   background: rgba(var(--global-dark-color));
   color: rgba(var(--light-block-txt));
   border: var(--global-border-width) solid rgba(var(--global-accent-2));
}

.darkblock {
   background-color:rgba(var(--global-dark-color));
   padding: 0.01rem 1rem;
   margin: 0.5rem 0 0.5rem 0.25rem;
   box-shadow: 0 0.25rem 0.3rem rgba(var(--global-black-color),0.5);
}

.styled-quote {
   background-color:rgba(var(--new-color-1));
   border-left: 0.5rem solid rgba(var(--global-dark-color));
   padding: 0.1rem 1rem;
   margin: 0.5rem 0 0.5rem 0.25rem;
   box-shadow: 0 0.25rem 0.3rem rgba(var(--global-black-color),0.5);
}

.dark-styled-quote {
   background-color:rgba(var(--global-dark-color));
   border-left: 0.5rem solid rgba(var(--new-color-1));
   padding: 0.1rem 1rem;
   margin: 0.5rem 0 0.5rem 0.25rem;
   box-shadow: 0 0.25rem 0.3rem rgba(var(--global-black-color),0.5);
}

.lightblock {
   background-color:rgba(var(--new-color-1));
   padding: 0.01rem 1rem;
   margin: 0.5rem 0 0.5rem 0.25rem;
   box-shadow: 0 0.25rem 0.3rem rgba(var(--global-black-color),0.5);
}

.light-bg {
   background: rgba(var(--global-dark-color));
}

.dark-bg {
   background: rgba(var(--global-accent-2));
}

.paperblock {
   width: auto;
   padding: 0.01rem 1rem;
   margin: 0.5rem 0 0.5rem 0.25rem;
   background: url(https://vivarium.wdfiles.com/local--files/backrooms%3Aoldpapertheme/thefinalone.jpg) repeat center;
   text-shadow: 1px 1px 1px rgba(var(--global-black-color),0.5);
   box-shadow: 0 0.25rem 0.3rem rgba(var(--global-black-color),0.5);
}

.paperblock2 {
   width: auto;
   padding: 0.01rem 1rem;
   margin: 0.5rem 0 0.5rem 0.25rem;
   background: linear-gradient(180deg, rgba(235, 196, 63,.3), rgba(235, 196, 63,.3)), url(https://vivarium.wdfiles.com/local--files/backrooms%3Aoldpapertheme/thefinalone.jpg) repeat center;
   text-shadow: 1px 1px 1px rgba(var(--global-black-color),0.5);
   box-shadow: 0 0.25rem 0.3rem rgba(var(--global-black-color),0.5);
}

.logo-dark {
   background: url(https://001-cn.wikidot.com/local--files/ytdm/logo-bg) center no-repeat;        
   border: solid 1px #000;
   padding: 1px 15px;
   box-shadow: 0 2.5px 3px rgba(var(--global-black-color),0.5);
   float: center;
   background-size:18%;
   background-color:rgba(var(--global-dark-color),0.7);
   margin:7px;
}

.logo-light {
   background: url(https://001-cn.wikidot.com/local--files/ytdm/logo-bg) center no-repeat;        
   border: solid 1px #000;
   padding: 1px 15px;
   box-shadow: 0 2.5px 3px rgba(var(--global-black-color),0.5);
   float: center;
   background-size:18%;
   background-color:rgba(var(--new-color-1),0.7);
   margin:7px;
}

.warning {
   border: solid 1px rgba(var(--global-accent-2));
   padding: 1px 15px;
   box-shadow: 0 2.5px 3px rgba(var(--global-black-color),0.5);
   float: center;
   background-color:rgba(var(--global-accent-2));
   margin:7px;
   color:rgba(var(--global-white-color));
}

.shadebox {
   margin: 2rem 0;
   background: rgba(var(--global-dark-color), 0.4);
   box-shadow: 0 0 0 1rem rgba(var(--global-dark-color), 0.4);
}

.yui-navset {
   border: var(--global-border-width) solid rgba(var(--global-accent-2));
}
.yui-navset .yui-nav,
.yui-navset .yui-navset-top .yui-nav {
   background: rgba(var(--global-dark-color));
   border-bottom: var(--global-border-width)  solid rgba(var(--global-accent-2));
}
:is(.yui-navset .yui-nav, .yui-navset .yui-navset-top .yui-nav) li {
   border-bottom: 0px;
}
:is(.yui-navset .yui-nav, .yui-navset .yui-navset-top .yui-nav) li:is(:hover, :focus) {
   background: rgba(var(--new-color-2));
}
:is(.yui-navset .yui-nav, .yui-navset .yui-navset-top .yui-nav) li.selected {
   background: rgba(var(--global-accent-2));
}
table.wiki-content-table {
   border: 1px solid rgba(var(--global-accent-2)) !important;
}
table.wiki-content-table th {
   border: 1px solid rgba(var(--global-accent-2)) !important;
}
table.wiki-content-table td {
   border: 1px solid rgba(var(--global-accent-2)) !important;
}
:is(.image-block,.scp-image-block) :is(.image-caption,.scp-image-caption) {
   background: rgba(var(--global-dark-color));
   border: 0px;
}
.hovertip {
    border: var(--global-border-width) solid rgb(86,75,61) !important;
    background-color: rgba(86,75,61,0.8) !important;
    color: rgba(223,194,158);
}
.code {
   background: rgba(233,194,138);
   border: var(--global-border-width) dashed rgba(var(--global-accent-2));
}
.owindow.owait .content::before {
   border: var(--global-border-width) solid rgba(var(--global-accent-2),0.7);
}
.owindow.owait .content::after {
   background: rgba(var(--global-dark-color));
}
.owindow {
   border: var(--global-border-width) solid rgba(var(--global-accent-2),0.3);
}
#page-options-container .page-options-bottom {
   border: 0px;
}
.btn:not(.page-rate-widget-box *, #login-status *, .owindow .button-bar > a[onclick*="cleanAll"]), a.action-area-close, .site-tools-box ul.nav.nav-pills a {
   background: rgba(223,194,158,0);
   border: 0px;
}
[type=radio], input[type=checkbox] {
   background-color: rgb(0, 0, 0, 0.4);
   border: .05rem solid rgb(0, 0, 0, 0.6);
}
:is(#edit-page-form, #new-post-form) {
   border: var(--global-border-width) solid rgb(86,75,61,0.6);
}
input.text, textarea, select {
   border: var(--global-border-width) solid rgb(86,75,61,0.6);
}
h1{font-size: 2.4rem;}
h2{font-size: 2.3rem;}
h3{font-size: 2.2rem;}
h4{font-size: 2.1rem;}
h5{font-size: 2.0rem;}
h6{font-size: 1.9rem;}
